INSERT INTO `chat_history` VALUES ('40', '3', 'user_3_session_1777404771926_uvjmaoegj', 'assistant', '# 青云门技能加点攻略\n\n## 职业定位\n\n> 青云门是诛仙世界中的远程法术输出职业，以高爆发和群体伤害著称。核心技能包括：**神剑御雷真诀、七劫斩龙诀、天诛剑气、天玄冰、真元护体**等。\n\n---\n\n## 技能加点推荐\n\n根据等级阶段的不同，加点方案如下：\n\n### 前期加点（1-40级）\n\n| 类型 | 技能 |\n|------|------|\n| 主加 | 神剑御雷真诀 |\n| 副加 | 七劫斩龙诀 |\n| 辅助 | 天玄冰 |\n\n### 中期加点（40-70级）\n\n| 类型 | 技能 |\n|------|------|\n| 主加 | 神剑御雷真诀、七劫斩龙诀 |\n| 副加 | 天诛剑气 |\n| 辅助 | 天玄冰、真元护体 |\n\n### 后期加点（70级以上）\n\n- **PVE**：神剑御雷真诀满、七劫斩龙诀满、天诛剑气满\n- **PVP**：根据实际情况调整控制技能\n\n---\n\n## 实战技巧\n\n1. 保持安全距离输出\n2. 合理使用控制技能\n3. 注意蓝量管理\n4. 团队配合优先\n\n---\n\n? **提示**：以上为青云门技能加点的核心内容，攻略文章中还有**装备选择**的详细建议（武器优先法术攻击高的法剑，防具选择增加法术暴击和命中的装备，饰品优先法术攻击和暴击率）。\n\n您可以在网站查看完整的《青云门技能加点攻略详解》攻略文章，了解更多细节。', '2026-04-29 03:33:27');
