INSERT INTO `knowledge_entry` VALUES ('5', '焚香谷火系法术', null, '焚香谷是火系法术输出职业，拥有持续伤害和范围控制能力。核心技能：焚天烈焰、火龙术、火墙等。', '1', null, null, '0', null, null, '焚香谷,火系,法术,持续伤害', '1654', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('6', '云梦宗治疗手法', null, '云梦宗是辅助治疗职业，拥有群体治疗和复活能力。治疗手法：优先保证坦克血量，注意团队站位。', '1', null, null, '0', null, null, '云梦宗,治疗,辅助,复活', '1456', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('7', '天音寺副本攻略', null, '天音寺副本是35级团队副本，推荐5人组队。BOSS打法：注意躲避范围技能，及时打断万佛朝宗。掉落：天音寺套装、高级强化石。', '2', null, null, '0', null, null, '天音寺,副本,攻略,35级', '2156', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('8', '普通副本通关指南', null, '普通副本适合新手玩家，难度较低。通关要点：注意BOSS技能预警，合理分配药品，团队配合。', '2', null, null, '0', null, null, '副本,通关,新手,指南', '3456', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('9', '精英副本打法', null, '精英副本难度较高，需要一定的装备基础。建议：组队前先检查装备，准备充足药品，熟悉BOSS机制。', '2', null, null, '0', null, null, '精英副本,攻略,难度,装备', '2890', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('10', '团队副本配置', null, '团队副本需要合理的职业配置。推荐配置：1坦克+2治疗+3输出，或根据副本特点调整。', '2', null, null, '0', null, null, '团队副本,配置,职业,配合', '1876', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('11', '装备强化技巧', null, '装备强化是提升战力的重要途径。强化技巧：+1到+10成功率较高，+11以上使用保护符，准备备用装备。', '3', null, null, '0', null, null, '装备,强化,技巧,战力', '4567', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('12', '装备获取途径', null, '装备获取途径：副本掉落、任务奖励、商城购买、活动兑换、玩家交易。优先获取适合职业的装备。', '3', null, null, '0', null, null, '装备,获取,途径,掉落', '3234', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('13', '装备精炼系统', null, '装备精炼可以进一步提升装备属性。精炼材料：精炼石、高级精炼石。注意：精炼有失败风险。', '3', null, null, '0', null, null, '装备,精炼,属性,材料', '2567', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('14', '宝石镶嵌指南', null, '宝石镶嵌可以为装备增加额外属性。宝石类型：攻击宝石、防御宝石、生命宝石等。根据职业选择合适宝石。', '3', null, null, '0', null, null, '装备,宝石,镶嵌,属性', '1987', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('15', '主线任务流程', null, '主线任务是游戏的核心剧情，提供大量经验和装备。建议：优先完成主线任务，了解游戏世界观。', '4', null, null, '0', null, null, '任务,主线,剧情,经验', '4123', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('16', '支线任务攻略', null, '支线任务补充主线剧情，提供额外奖励。建议：在做主线的同时顺路完成支线任务。', '4', null, null, '0', null, null, '任务,支线,攻略,奖励', '2890', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('17', '日常任务指南', null, '日常任务是稳定的经验和金币来源。每日必做：师门任务、帮派任务、悬赏任务等。', '4', null, null, '0', null, null, '任务,日常,经验,金币', '3654', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('18', '周常任务介绍', null, '周常任务每周刷新，奖励丰厚。包括：周副本、周活动、周挑战等。建议组队完成。', '4', null, null, '0', null, null, '任务,周常,奖励,组队', '2134', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('19', '伙伴获取方法', null, '伙伴获取途径：主线任务、招募系统、活动奖励、商城购买。品质越高，成长潜力越大。', '5', null, null, '0', null, null, '伙伴,获取,招募,品质', '2876', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('20', '伙伴培养攻略', null, '伙伴培养包括：升级、升星、技能、装备。建议：优先培养主力伙伴，合理分配资源。', '5', null, null, '0', null, null, '伙伴,培养,升级,升星', '3234', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('21', '伙伴搭配技巧', null, '伙伴搭配要考虑职业互补。推荐搭配：输出+坦克+辅助，根据战斗场景调整阵容。', '5', null, null, '0', null, null, '伙伴,搭配,阵容,技巧', '2567', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('22', '伙伴技能升级', null, '伙伴技能升级需要技能书。技能书获取：副本掉落、活动奖励、商城购买。优先升级主动技能。', '5', null, null, '0', null, null, '伙伴,技能,升级,技能书', '1876', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('23', '竞技场技巧', null, '竞技场是展示实力的舞台。技巧：了解各职业特点，合理使用药品，注意技能CD管理，观察对手习惯。', '6', null, null, '0', null, null, 'PVP,竞技场,技巧,排名', '2890', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('24', '帮派战攻略', null, '帮派战是大型PVP活动。攻略：听从指挥，集中火力，保护治疗，合理利用地形。', '6', null, null, '0', null, null, 'PVP,帮派战,攻略,团队', '2134', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('25', '野外PK技巧', null, '野外PK需要注意红名机制。技巧：选择合适时机，注意周围环境，准备好逃跑路线。', '6', null, null, '0', null, null, 'PVP,野外,PK,红名', '1654', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('26', '限时活动介绍', null, '限时活动提供丰厚奖励。关注游戏公告，及时参与活动，获取稀有道具和装备。', '7', null, null, '0', null, null, '活动,限时,奖励,道具', '3456', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('27', '节日活动攻略', null, '节日活动通常在现实节日期间开放。攻略：完成活动任务，兑换节日限定奖励。', '7', null, null, '0', null, null, '活动,节日,攻略,限定', '2890', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('28', '帮派系统玩法', null, '帮派系统提供社交和团队玩法。功能：帮派任务、帮派技能、帮派商店、帮派战等。', '8', null, null, '0', null, null, '系统,帮派,社交,团队', '3234', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('29', '交易系统说明', null, '交易系统支持玩家间物品交换。注意：交易税、绑定物品无法交易、注意防骗。', '8', null, null, '0', null, null, '系统,交易,物品,防骗', '2567', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
INSERT INTO `knowledge_entry` VALUES ('30', '社交系统介绍', null, '社交系统包括：好友、师徒、结婚等。建立良好的社交关系，可以获得游戏帮助和乐趣。', '8', null, null, '0', null, null, '系统,社交,好友,师徒', '1987', '1', '2026-04-28 01:59:40', '2026-04-28 01:59:40');
